<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Falling Sand Sandbox</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #090b10;
      --panel: #121722;
      --panel-2: #191f2c;
      --border: #2a3242;
      --text: #eef2f8;
      --muted: #929bad;
      --accent: #68a8ff;
    }

    * {
      box-sizing: border-box;
    }

    html,
    body {
      min-height: 100%;
      margin: 0;
    }

    body {
      display: grid;
      place-items: center;
      padding: 24px;
      overflow: auto;
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background:
        radial-gradient(circle at 50% 8%, #182135 0, transparent 35%),
        radial-gradient(circle at 15% 85%, #101b24 0, transparent 28%),
        var(--bg);
    }

    .app {
      width: min(100%, 920px);
      display: grid;
      justify-items: center;
      gap: 16px;
    }

    header {
      text-align: center;
    }

    h1 {
      margin: 0;
      font-size: clamp(1.55rem, 3vw, 2.25rem);
      letter-spacing: 0.02em;
    }

    .subtitle {
      margin: 6px 0 0;
      color: var(--muted);
      font-size: 0.94rem;
    }

    .toolbar {
      width: min(100%, 760px);
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      align-items: center;
      gap: 8px;
      padding: 11px;
      border: 1px solid var(--border);
      border-radius: 16px;
      background: color-mix(in srgb, var(--panel) 92%, transparent);
      box-shadow: 0 12px 35px #0007;
    }

    button {
      min-height: 39px;
      border: 1px solid #313a4c;
      border-radius: 10px;
      padding: 8px 13px;
      color: var(--text);
      font: inherit;
      font-size: 0.9rem;
      font-weight: 700;
      background: linear-gradient(#222938, #191f2b);
      box-shadow: inset 0 1px #ffffff0c, 0 3px 8px #0004;
      cursor: pointer;
      transition: transform 100ms ease, border-color 120ms ease,
        background 120ms ease, box-shadow 120ms ease;
    }

    button:hover {
      border-color: #536078;
      transform: translateY(-1px);
    }

    button:active {
      transform: translateY(1px);
    }

    button:focus-visible,
    input:focus-visible {
      outline: 2px solid var(--accent);
      outline-offset: 2px;
    }

    button.material {
      position: relative;
      padding-left: 31px;
    }

    button.material::before {
      content: "";
      position: absolute;
      left: 11px;
      top: 50%;
      width: 11px;
      height: 11px;
      border-radius: 4px;
      transform: translateY(-50%);
      background: var(--swatch);
      box-shadow: 0 0 9px color-mix(in srgb, var(--swatch) 55%, transparent);
    }

    button.material[aria-pressed="true"] {
      border-color: var(--swatch);
      background: color-mix(in srgb, var(--swatch) 18%, #18202c);
      box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--swatch) 50%, transparent),
        0 5px 14px #0006;
    }

    #mat-sand { --swatch: #e7bd55; }
    #mat-water { --swatch: #398df2; }
    #mat-wall { --swatch: #8b93a2; }
    #mat-acid { --swatch: #73ed5d; }
    #mat-empty { --swatch: #394150; }

    .separator {
      width: 1px;
      height: 29px;
      margin: 0 2px;
      background: var(--border);
    }

    .brush-control {
      display: flex;
      align-items: center;
      gap: 8px;
      margin-left: 3px;
      color: var(--muted);
      font-size: 0.85rem;
      white-space: nowrap;
    }

    input[type="range"] {
      width: 82px;
      accent-color: var(--accent);
      cursor: pointer;
    }

    .canvas-shell {
      position: relative;
      padding: 8px;
      border: 1px solid #30394a;
      border-radius: 17px;
      background: linear-gradient(145deg, #1c2432, #0d1119);
      box-shadow: 0 25px 60px #000a, inset 0 1px #ffffff0b;
    }

    #sand {
      display: block;
      width: clamp(400px, 68vmin, 640px);
      height: clamp(400px, 68vmin, 640px);
      min-width: 400px;
      min-height: 400px;
      border-radius: 10px;
      background: #090c12;
      image-rendering: pixelated;
      cursor: crosshair;
      touch-action: none;
      user-select: none;
    }

    .status {
      width: min(100%, 650px);
      display: flex;
      justify-content: space-between;
      gap: 20px;
      color: var(--muted);
      font-size: 0.82rem;
    }

    .status strong {
      color: #cbd3df;
    }

    @media (max-width: 520px) {
      body {
        place-items: start center;
        padding: 12px;
      }

      .separator {
        display: none;
      }

      .status {
        flex-direction: column;
        align-items: center;
        gap: 3px;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <header>
      <h1>Elemental Sandbox</h1>
      <p class="subtitle">Paint, pour, dissolve, and build.</p>
    </header>

    <section class="toolbar" aria-label="Sandbox controls">
      <button class="material" id="mat-sand" data-material="sand" aria-pressed="true">Sand</button>
      <button class="material" id="mat-water" data-material="water" aria-pressed="false">Water</button>
      <button class="material" id="mat-wall" data-material="wall" aria-pressed="false">Wall</button>
      <button class="material" id="mat-acid" data-material="acid" aria-pressed="false">Acid</button>
      <button class="material" id="mat-empty" data-material="empty" aria-pressed="false">Eraser</button>

      <span class="separator" aria-hidden="true"></span>

      <label class="brush-control">
        Brush
        <input id="brush" type="range" min="1" max="6" value="2">
        <span id="brush-value">2</span>
      </label>

      <span class="separator" aria-hidden="true"></span>

      <button id="pause" aria-pressed="false">Pause</button>
      <button id="clear">Clear</button>
    </section>

    <div class="canvas-shell">
      <canvas
        id="sand"
        width="600"
        height="600"
        aria-label="Falling sand simulation canvas"
      ></canvas>
    </div>

    <div class="status">
      <span><strong>Drag</strong> to paint · right-drag to erase</span>
      <span id="particle-count">0 active cells</span>
    </div>
  </main>

  <script>
    (() => {
      "use strict";

      const W = 100;
      const H = 100;

      const EMPTY = 0;
      const SAND = 1;
      const WATER = 2;
      const WALL = 3;
      const ACID = 4;

      const names = ["empty", "sand", "water", "wall", "acid"];
      const values = Object.freeze({
        empty: EMPTY,
        sand: SAND,
        water: WATER,
        wall: WALL,
        acid: ACID
      });

      const grid = new Uint8Array(W * H);
      const moved = new Uint8Array(W * H);

      const canvas = document.getElementById("sand");
      const ctx = canvas.getContext("2d", { alpha: false });
      const countLabel = document.getElementById("particle-count");
      const materialButtons = [...document.querySelectorAll(".material")];
      const pauseButton = document.getElementById("pause");
      const brushInput = document.getElementById("brush");
      const brushValue = document.getElementById("brush-value");

      const cellWidth = canvas.width / W;
      const cellHeight = canvas.height / H;

      let selected = "sand";
      let brushRadius = Number(brushInput.value);
      let paused = false;
      let painting = false;
      let paintMaterial = selected;
      let previousCell = null;
      let seed = 0x7f4a7c15;

      function index(x, y) {
        return y * W + x;
      }

      function inBounds(x, y) {
        return x >= 0 && x < W && y >= 0 && y < H;
      }

      function randomBit() {
        seed ^= seed << 13;
        seed ^= seed >>> 17;
        seed ^= seed << 5;
        seed >>>= 0;
        return seed & 1;
      }

      function moveCell(from, to) {
        grid[to] = grid[from];
        grid[from] = EMPTY;
        moved[to] = 1;
      }

      function shuffledDirections() {
        return randomBit() ? [-1, 1] : [1, -1];
      }

      /*
       * Sink sand into liquid without repeatedly pushing liquid straight up
       * through a falling column. The displaced liquid is moved around the
       * incoming grain to a nearby side opening. If there is no local opening,
       * the grain waits until the liquid can escape.
       */
      function sinkSand(x, y, targetX, targetY) {
        const from = index(x, y);
        const target = index(targetX, targetY);
        const liquid = grid[target];

        if ((liquid !== WATER && liquid !== ACID) || moved[target]) {
          return false;
        }

        const dirs = shuffledDirections();
        const candidates = [];

        for (const d of dirs) candidates.push([targetX + d, targetY]);
        for (const d of dirs) candidates.push([x + d, y]);

        for (const [cx, cy] of candidates) {
          if (!inBounds(cx, cy)) continue;
          const candidate = index(cx, cy);
          if (candidate === from || candidate === target) continue;

          if (grid[candidate] === EMPTY && !moved[candidate]) {
            grid[from] = EMPTY;
            grid[target] = SAND;
            grid[candidate] = liquid;
            moved[target] = 1;
            moved[candidate] = 1;
            return true;
          }
        }

        return false;
      }

      function updateSand(x, y, i) {
        if (y >= H - 1) return;

        const below = index(x, y + 1);
        if (grid[below] === EMPTY) {
          moveCell(i, below);
          return;
        }

        if (grid[below] === WATER || grid[below] === ACID) {
          if (sinkSand(x, y, x, y + 1)) return;
        }

        const dirs = shuffledDirections();
        for (const dx of dirs) {
          const nx = x + dx;
          const ny = y + 1;
          if (!inBounds(nx, ny)) continue;

          const diagonal = index(nx, ny);
          if (grid[diagonal] === EMPTY) {
            moveCell(i, diagonal);
            return;
          }
        }
      }

      function dissolveNeighbors(x, y) {
        const neighbors = [
          [x, y + 1],
          [x - 1, y],
          [x + 1, y]
        ];

        for (const [nx, ny] of neighbors) {
          if (!inBounds(nx, ny)) continue;
          const ni = index(nx, ny);
          if (grid[ni] === SAND || grid[ni] === WALL) {
            grid[ni] = EMPTY;
            moved[ni] = 0;
          }
        }
      }

      function updateLiquid(x, y, i, isAcid) {
        if (isAcid) dissolveNeighbors(x, y);

        if (y < H - 1) {
          const below = index(x, y + 1);
          if (grid[below] === EMPTY) {
            moveCell(i, below);
            return;
          }

          const diagonalDirs = shuffledDirections();
          for (const dx of diagonalDirs) {
            const nx = x + dx;
            const ny = y + 1;
            if (!inBounds(nx, ny)) continue;

            const diagonal = index(nx, ny);
            if (grid[diagonal] === EMPTY) {
              moveCell(i, diagonal);
              return;
            }
          }
        }

        const horizontalDirs = shuffledDirections();
        for (const dx of horizontalDirs) {
          const nx = x + dx;
          if (!inBounds(nx, y)) continue;

          const side = index(nx, y);
          if (grid[side] === EMPTY) {
            moveCell(i, side);
            return;
          }
        }
      }

      function step() {
        moved.fill(0);

        // Bottom-to-top processing prevents any particle from cascading down
        // through multiple rows during a single simulation step.
        for (let y = H - 1; y >= 0; y--) {
          const reverse = Boolean(randomBit());

          for (let p = 0; p < W; p++) {
            const x = reverse ? W - 1 - p : p;
            const i = index(x, y);

            if (moved[i]) continue;

            const material = grid[i];
            if (material === SAND) {
              updateSand(x, y, i);
            } else if (material === WATER) {
              updateLiquid(x, y, i, false);
            } else if (material === ACID) {
              updateLiquid(x, y, i, true);
            }
          }
        }
      }

      function render() {
        ctx.fillStyle = "#090c12";
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        let active = 0;

        for (let y = 0; y < H; y++) {
          for (let x = 0; x < W; x++) {
            const material = grid[index(x, y)];
            if (material === EMPTY) continue;
            active++;

            const variation = ((x * 31 + y * 17) & 7);

            if (material === SAND) {
              ctx.fillStyle = variation < 3 ? "#f1ca62" : "#d9aa42";
            } else if (material === WATER) {
              ctx.fillStyle = variation < 2 ? "#55a6ff" : "#2479dc";
            } else if (material === WALL) {
              ctx.fillStyle = variation < 2 ? "#a2a9b5" : "#717987";
            } else {
              ctx.fillStyle = variation < 3 ? "#91ff69" : "#45ce42";
            }

            const px = x * cellWidth;
            const py = y * cellHeight;
            ctx.fillRect(px, py, cellWidth + 0.15, cellHeight + 0.15);

            if (material === WATER || material === ACID) {
              ctx.fillStyle = material === WATER ? "#b3ddff45" : "#d5ffb84d";
              ctx.fillRect(px, py, cellWidth, Math.max(1, cellHeight * 0.2));
            } else if (material === WALL && variation === 0) {
              ctx.fillStyle = "#cbd0d733";
              ctx.fillRect(px, py, cellWidth, 1);
            }
          }
        }

        countLabel.textContent = `${active.toLocaleString()} active cell${active === 1 ? "" : "s"}`;
      }

      function clearGrid() {
        grid.fill(EMPTY);
        moved.fill(0);
        seed = 0x7f4a7c15;
        render();
      }

      function apiGet(x, y) {
        x = Math.trunc(Number(x));
        y = Math.trunc(Number(y));
        if (!inBounds(x, y)) return "wall";
        return names[grid[index(x, y)]];
      }

      function apiSet(x, y, material) {
        x = Math.trunc(Number(x));
        y = Math.trunc(Number(y));

        if (!inBounds(x, y)) return;
        if (!Object.prototype.hasOwnProperty.call(values, material)) {
          throw new TypeError(`Unknown material: ${material}`);
        }

        grid[index(x, y)] = values[material];
        render();
      }

      function apiTick(n = 1) {
        n = Math.max(0, Math.floor(Number(n) || 0));
        for (let i = 0; i < n; i++) step();
        render();
      }

      window.sim = Object.freeze({
        w: W,
        h: H,
        tick: apiTick,
        get: apiGet,
        set: apiSet,
        clear: clearGrid
      });

      function selectMaterial(material) {
        selected = material;
        for (const button of materialButtons) {
          button.setAttribute(
            "aria-pressed",
            String(button.dataset.material === selected)
          );
        }
      }

      materialButtons.forEach(button => {
        button.addEventListener("click", () => {
          selectMaterial(button.dataset.material);
        });
      });

      brushInput.addEventListener("input", () => {
        brushRadius = Number(brushInput.value);
        brushValue.textContent = String(brushRadius);
      });

      document.getElementById("clear").addEventListener("click", clearGrid);

      pauseButton.addEventListener("click", () => {
        paused = !paused;
        pauseButton.textContent = paused ? "Resume" : "Pause";
        pauseButton.setAttribute("aria-pressed", String(paused));
      });

      function eventToCell(event) {
        const rect = canvas.getBoundingClientRect();
        return {
          x: Math.max(0, Math.min(W - 1,
            Math.floor((event.clientX - rect.left) / rect.width * W))),
          y: Math.max(0, Math.min(H - 1,
            Math.floor((event.clientY - rect.top) / rect.height * H)))
        };
      }

      function paintPoint(cx, cy, material) {
        const radius = brushRadius - 1;
        const radiusSquared = (radius + 0.45) * (radius + 0.45);

        for (let dy = -radius; dy <= radius; dy++) {
          for (let dx = -radius; dx <= radius; dx++) {
            if (dx * dx + dy * dy > radiusSquared) continue;

            const x = cx + dx;
            const y = cy + dy;
            if (inBounds(x, y)) {
              grid[index(x, y)] = values[material];
            }
          }
        }
      }

      function paintLine(from, to, material) {
        let x0 = from.x;
        let y0 = from.y;
        const x1 = to.x;
        const y1 = to.y;
        const dx = Math.abs(x1 - x0);
        const sx = x0 < x1 ? 1 : -1;
        const dy = -Math.abs(y1 - y0);
        const sy = y0 < y1 ? 1 : -1;
        let error = dx + dy;

        while (true) {
          paintPoint(x0, y0, material);
          if (x0 === x1 && y0 === y1) break;

          const doubled = error * 2;
          if (doubled >= dy) {
            error += dy;
            x0 += sx;
          }
          if (doubled <= dx) {
            error += dx;
            y0 += sy;
          }
        }
      }

      canvas.addEventListener("pointerdown", event => {
        if (event.button !== 0 && event.button !== 2) return;
        event.preventDefault();

        painting = true;
        canvas.setPointerCapture(event.pointerId);
        paintMaterial = event.button === 2 ? "empty" : selected;
        previousCell = eventToCell(event);
        paintPoint(previousCell.x, previousCell.y, paintMaterial);
        render();
      });

      canvas.addEventListener("pointermove", event => {
        if (!painting) return;
        event.preventDefault();

        const current = eventToCell(event);
        paintLine(previousCell, current, paintMaterial);
        previousCell = current;
        render();
      });

      function stopPainting(event) {
        if (!painting) return;
        painting = false;
        previousCell = null;

        if (canvas.hasPointerCapture(event.pointerId)) {
          canvas.releasePointerCapture(event.pointerId);
        }
      }

      canvas.addEventListener("pointerup", stopPainting);
      canvas.addEventListener("pointercancel", stopPainting);
      canvas.addEventListener("contextmenu", event => event.preventDefault());

      let lastTime = performance.now();
      let accumulator = 0;
      const stepDuration = 1000 / 35;

      function animate(now) {
        const elapsed = Math.min(100, now - lastTime);
        lastTime = now;

        if (!paused && !painting) {
          accumulator += elapsed;
          let iterations = 0;

          while (accumulator >= stepDuration && iterations < 4) {
            step();
            accumulator -= stepDuration;
            iterations++;
          }

          if (iterations) render();
        } else {
          accumulator = 0;
        }

        requestAnimationFrame(animate);
      }

      render();
      requestAnimationFrame(animate);
    })();
  </script>
</body>
</html>
